def solve(grid):
    grid = [row[:] for row in grid]
    H, W = len(grid), len(grid[0])
    blocks = []
    for r in range(H-2):
        for c in range(W-2):
            center = grid[r+1][c+1]
            border = grid[r][c+1]
            if center == 0 or border == 0 or center == 5 or border == 5:
                continue
            corners = [grid[r][c], grid[r][c+2], grid[r+2][c], grid[r+2][c+2]]
            edges = [grid[r][c+1], grid[r+1][c], grid[r+1][c+2], grid[r+2][c+1]]
            if all(e == border for e in edges) and all(co == border for co in corners):
                blocks.append((r, c, border, center))
    border_map = {}
    for idx, (r, c, brd, ctr) in enumerate(blocks):
        border_map[brd] = idx
    edges = {}
    incoming = {i: None for i in range(len(blocks))}
    for idx, (r, c, brd, ctr) in enumerate(blocks):
        target = border_map.get(ctr)
        if target is not None and target != idx:
            edges[idx] = target
            incoming[target] = idx
    sources = [i for i in range(len(blocks)) if incoming[i] is None]
    erased_set = set()
    new_centers = {}
    for src in sources:
        chain = []
        cur = src
        visited = set()
        while cur is not None and cur not in visited:
            chain.append(cur)
            visited.add(cur)
            cur = edges.get(cur)
        for pos, block_idx in enumerate(chain):
            if pos % 2 == 0 and pos < len(chain) - 1:
                next_block = chain[pos + 1]
                new_centers[block_idx] = blocks[next_block][3]
            else:
                erased_set.add(block_idx)
    out = [row[:] for row in grid]
    for idx in erased_set:
        r, c, brd, ctr = blocks[idx]
        for dr in range(3):
            for dc in range(3):
                out[r+dr][c+dc] = 0
    for idx, new_ctr in new_centers.items():
        r, c, brd, ctr = blocks[idx]
        out[r+1][c+1] = new_ctr
    return out

